import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);

        // Input the number of test cases
        int t = sc.nextInt();

        // Process each test case
        while (t-- > 0) {
            // Input the size of the array
            int n = sc.nextInt();
            int[] arr = new int[n];

            // Input the elements of the array
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
            }

            // Initialize maxsum to the smallest integer value
            int maxsum = Integer.MIN_VALUE;

            // Calculate the maximum sum of any subarray
            for (int i = 0; i < n; i++) {
                for (int j = i; j < n; j++) {
                    int sum = 0;
                    for (int k = i; k <= j; k++) {
                        sum += arr[k];
                    }
                    maxsum = Math.max(maxsum, sum);
                }
            }

            // Print the maximum sum for the current test case
            System.out.println(maxsum);
        }

        // Close the scanner
        sc.close();
    }
}

