function maxSubarraySum(tests) {
    const T = parseInt(tests[0]);
    let currentIndex = 1;

    for (let i = 0; i < T; i++) {
        const N = parseInt(tests[currentIndex]);
        const arr = tests[currentIndex + 1].split(' ').map(Number);
        let maxSum = -Infinity;

        // Compute maximum subarray sum using a brute-force approach
        for (let i = 0; i < N; i++) {
            for (let j = i; j < N; j++) {
                let sum = 0;
                for (let k = i; k <= j; k++) {
                    sum += arr[k];
                }
                maxSum = Math.max(maxSum, sum);
            }
        }

        console.log(maxSum);
        currentIndex += 2; // Move to the next test case
    }
}
